    """Fewest hops (at most 'limit') to a node worth at least the threshold, or -1."""
    adj = spec["adj"]; vals = spec["vals"]; start = spec["start"]
    limit = spec["limit"]; threshold = spec["threshold"]
    depth = {start: 0}; queue = [start]; i = 0
    while i < len(queue):
        n = queue[i]; i += 1
        if vals[n] >= threshold:
            return depth[n]
        if depth[n] < limit:
            for t in adj.get(n, []):
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return -1

