def peak_radius_count(spec: dict) -> int:
    """Count nodes within the radius of the highest-valued reachable node."""
    adj = spec["adj"]; vals = spec["vals"]
    seen = []
    queue = [spec["start"]]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    peak = seen[0]
    for n in seen:
        if vals[n] > vals[peak] or (vals[n] == vals[peak] and n < peak):
            peak = n
    depth = {peak: 0}
    queue = [peak]
    while queue:
        n = queue.pop(0)
        for m in adj[n]:
            if m not in depth:
                depth[m] = depth[n] + 1
                queue.append(m)
    count = 0
    for n in depth:
        if depth[n] <= spec["radius"]:
            count += 1
    return count

